// // This register outputs the previous input value on each positive clock edge and resets to 11111111 when a synchronous active high reset signal is asserted.
module register (
  input clk,
  input reset,
  input [7:0] in,
  output reg [7:0] out);always @(posedge clk) begin
    if (reset) out <= 8'b00000000;
    else out <= in;
end

endmodule
